"""Java to Neo4j Graph GeneratorParses any Java file and generates Cypher to create the graph"""from tree_sitter import Parserfrom tree_sitter_language_pack import get_languagefrom pathlib import Pathdef parse_java_file(file_path):    """Parse a Java file with tree-sitter"""    with open(file_path, 'r', encoding='utf-8') as f:        code = f.read()    parser = Parser(get_language('java'))    tree = parser.parse(bytes(code, 'utf8'))    return tree, codedef extract_package_name(tree, code):    """Extract package declaration"""    for node in tree.root_node.children:        if node.type == 'package_declaration':            for child in node.children:                if child.type == 'scoped_identifier':                    return code[child.start_byte:child.end_byte]    return Nonedef extract_imports(tree, code):    """Extract all import statements"""    imports = []    for node in tree.root_node.children:        if node.type == 'import_declaration':            import_text = code[node.start_byte:node.end_byte]            # Extract the actual class/package being imported            for child in node.children:                if child.type == 'scoped_identifier':                    imports.append(code[child.start_byte:child.end_byte])    return importsdef extract_class_info(class_node, code, file_path, package):    """Extract class information"""    class_info = {        'name': None,        'full_name': None,        'file': file_path,        'start_line': class_node.start_point[0] + 1,        'end_line': class_node.end_point[0] + 1,        'access_modifier': 'package-private',        'is_abstract': False,        'is_static': False,        'annotations': [],        'extends': None,        'implements': []    }    for child in class_node.children:        # Get class name        if child.type == 'identifier':            class_info['name'] = code[child.start_byte:child.end_byte]            if package:                class_info['full_name'] = f"{package}.{class_info['name']}"            else:                class_info['full_name'] = class_info['name']        # Get modifiers (public, abstract, static, annotations)        elif child.type == 'modifiers':            for mod in child.children:                if mod.type == 'marker_annotation':                    ann = code[mod.start_byte:mod.end_byte]                    class_info['annotations'].append(ann)                elif mod.type == 'annotation':                    ann = code[mod.start_byte:mod.end_byte]                    class_info['annotations'].append(ann)                elif code[mod.start_byte:mod.end_byte] == 'public':                    class_info['access_modifier'] = 'public'                elif code[mod.start_byte:mod.end_byte] == 'private':                    class_info['access_modifier'] = 'private'                elif code[mod.start_byte:mod.end_byte] == 'protected':                    class_info['access_modifier'] = 'protected'                elif code[mod.start_byte:mod.end_byte] == 'abstract':                    class_info['is_abstract'] = True                elif code[mod.start_byte:mod.end_byte] == 'static':                    class_info['is_static'] = True        # Get parent class (extends)        elif child.type == 'superclass':            for sc_child in child.children:                if sc_child.type == 'type_identifier':                    class_info['extends'] = code[sc_child.start_byte:sc_child.end_byte]        # Get interfaces (implements)        elif child.type == 'super_interfaces':            for si_child in child.children:                if si_child.type == 'type_identifier':                    class_info['implements'].append(code[si_child.start_byte:si_child.end_byte])    return class_infodef extract_method_info(method_node, code, class_name):    """Extract method information"""    method_info = {        'name': None,        'full_name': None,        'class': class_name,        'start_line': method_node.start_point[0] + 1,        'end_line': method_node.end_point[0] + 1,        'access_modifier': 'package-private',        'is_static': False,        'is_abstract': False,        'is_override': False,        'is_constructor': False,        'return_type': None,        'annotations': [],        'throws': [],        'catches': [],        'calls': []    }    for child in method_node.children:        # Get method name        if child.type == 'identifier':            method_info['name'] = code[child.start_byte:child.end_byte]            # Build full name with parameters (simplified)            method_info['full_name'] = f"{class_name}.{method_info['name']}"        # Get modifiers        elif child.type == 'modifiers':            for mod in child.children:                if mod.type == 'marker_annotation':                    ann = code[mod.start_byte:mod.end_byte]                    method_info['annotations'].append(ann)                    if ann == '@Override':                        method_info['is_override'] = True                elif mod.type == 'annotation':                    ann = code[mod.start_byte:mod.end_byte]                    method_info['annotations'].append(ann)                elif code[mod.start_byte:mod.end_byte] == 'public':                    method_info['access_modifier'] = 'public'                elif code[mod.start_byte:mod.end_byte] == 'private':                    method_info['access_modifier'] = 'private'                elif code[mod.start_byte:mod.end_byte] == 'protected':                    method_info['access_modifier'] = 'protected'                elif code[mod.start_byte:mod.end_byte] == 'static':                    method_info['is_static'] = True                elif code[mod.start_byte:mod.end_byte] == 'abstract':                    method_info['is_abstract'] = True        # Get return type        elif child.type in ['type_identifier', 'void_type', 'integral_type']:            method_info['return_type'] = code[child.start_byte:child.end_byte]        # Get throws clause        elif child.type == 'throws':            for throws_child in child.children:                if throws_child.type == 'type_identifier':                    exc = code[throws_child.start_byte:throws_child.end_byte]                    method_info['throws'].append(exc)        # Get method body (for catches and calls)        elif child.type == 'block':            extract_from_block(child, code, method_info)    return method_infodef extract_from_block(block_node, code, method_info):    """Extract catches and calls from method body"""    def recurse(node):        # Find try-catch blocks        if node.type == 'try_statement':            for child in node.children:                if child.type == 'catch_clause':                    for catch_child in child.children:                        if catch_child.type == 'catch_formal_parameter':                            for param_child in catch_child.children:                                if param_child.type == 'catch_type':                                    # Can have multiple exception types separated by |                                    for type_child in param_child.children:                                        if type_child.type == 'type_identifier':                                            exc = code[type_child.start_byte:type_child.end_byte]                                            if exc not in method_info['catches']:                                                method_info['catches'].append(exc)        # Find method calls        elif node.type == 'method_invocation':            for child in node.children:                if child.type == 'identifier':                    call = code[child.start_byte:child.end_byte]                    if call not in method_info['calls']:                        method_info['calls'].append(call)                    break        # Recurse into children        for child in node.children:            recurse(child)    recurse(block_node)def find_all_nodes_of_type(node, node_type, results=None):    """Recursively find all nodes of a specific type"""    if results is None:        results = []    if node.type == node_type:        results.append(node)    for child in node.children:        find_all_nodes_of_type(child, node_type, results)    return resultsdef generate_cypher(java_file_path):    """    Parse Java file and generate Cypher statements    """    # Parse the file    tree, code = parse_java_file(java_file_path)    # Extract basic info    package = extract_package_name(tree, code)    imports = extract_imports(tree, code)    # Storage    cypher_statements = []    entities = {        'files': [],        'classes': [],        'interfaces': [],        'methods': [],        'exceptions': set(),        'annotations': set()    }    relationships = []    # Add comment header    cypher_statements.append("// " + "="*60)    cypher_statements.append(f"// Auto-generated Cypher for: {java_file_path}")    cypher_statements.append("// " + "="*60)    cypher_statements.append("")    # Create File node    file_name = Path(java_file_path).name    file_path_str = str(java_file_path)    cypher_statements.append("// CREATE FILE")    cypher_statements.append(f"CREATE (file:File {{")    cypher_statements.append(f"    path: '{file_path_str}',")    cypher_statements.append(f"    name: '{file_name}',")    cypher_statements.append(f"    language: 'java'")    if package:        cypher_statements.append(f"    , package: '{package}'")    cypher_statements.append("});")    cypher_statements.append("")    # Find all classes    class_nodes = find_all_nodes_of_type(tree.root_node, 'class_declaration')    for class_node in class_nodes:        class_info = extract_class_info(class_node, code, file_path_str, package)        entities['classes'].append(class_info)        # Create Class node        cypher_statements.append(f"// CREATE CLASS: {class_info['name']}")        cypher_statements.append(f"CREATE (class_{class_info['name']}:Class {{")        cypher_statements.append(f"    name: '{class_info['name']}',")        cypher_statements.append(f"    full_name: '{class_info['full_name']}',")        cypher_statements.append(f"    file: '{file_path_str}',")        cypher_statements.append(f"    start_line: {class_info['start_line']},")        cypher_statements.append(f"    end_line: {class_info['end_line']},")        cypher_statements.append(f"    access_modifier: '{class_info['access_modifier']}',")        cypher_statements.append(f"    is_abstract: {str(class_info['is_abstract']).lower()}")        cypher_statements.append("});")        cypher_statements.append("")        # Create CONTAINS relationship: File -> Class        cypher_statements.append(f"// File CONTAINS Class")        cypher_statements.append(f"MATCH (f:File {{path: '{file_path_str}'}})")        cypher_statements.append(f"MATCH (c:Class {{full_name: '{class_info['full_name']}'}})")        cypher_statements.append(f"CREATE (f)-[:CONTAINS]->(c);")        cypher_statements.append("")        # Handle inheritance        if class_info['extends']:            cypher_statements.append(f"// CREATE PARENT CLASS: {class_info['extends']}")            cypher_statements.append(f"MERGE (parent:Class {{name: '{class_info['extends']}', is_external: true}});")            cypher_statements.append(f"MATCH (c:Class {{full_name: '{class_info['full_name']}'}})")            cypher_statements.append(f"MATCH (p:Class {{name: '{class_info['extends']}'}})")            cypher_statements.append(f"CREATE (c)-[:INHERITS]->(p);")            cypher_statements.append("")        # Handle interfaces        for interface in class_info['implements']:            cypher_statements.append(f"// CREATE INTERFACE: {interface}")            cypher_statements.append(f"MERGE (iface:Interface {{name: '{interface}', is_external: true}});")            cypher_statements.append(f"MATCH (c:Class {{full_name: '{class_info['full_name']}'}})")            cypher_statements.append(f"MATCH (i:Interface {{name: '{interface}'}})")            cypher_statements.append(f"CREATE (c)-[:IMPLEMENTS]->(i);")            cypher_statements.append("")        # Handle class annotations        for annotation in class_info['annotations']:            entities['annotations'].add(annotation)            cypher_statements.append(f"// Annotation on Class")            cypher_statements.append(f"MERGE (ann:Annotation {{name: '{annotation}'}});")            cypher_statements.append(f"MATCH (a:Annotation {{name: '{annotation}'}})")            cypher_statements.append(f"MATCH (c:Class {{full_name: '{class_info['full_name']}'}})")            cypher_statements.append(f"CREATE (a)-[:ANNOTATES]->(c);")            cypher_statements.append("")        # Find methods in this class        method_nodes = find_all_nodes_of_type(class_node, 'method_declaration')        for method_node in method_nodes:            method_info = extract_method_info(method_node, code, class_info['full_name'])            entities['methods'].append(method_info)            # Create Method node            method_id = f"method_{class_info['name']}_{method_info['name']}"            cypher_statements.append(f"// CREATE METHOD: {method_info['name']}")            cypher_statements.append(f"CREATE ({method_id}:Method {{")            cypher_statements.append(f"    name: '{method_info['name']}',")            cypher_statements.append(f"    full_name: '{method_info['full_name']}',")            cypher_statements.append(f"    class: '{class_info['full_name']}',")            cypher_statements.append(f"    start_line: {method_info['start_line']},")            cypher_statements.append(f"    end_line: {method_info['end_line']},")            cypher_statements.append(f"    access_modifier: '{method_info['access_modifier']}',")            cypher_statements.append(f"    is_static: {str(method_info['is_static']).lower()},")            cypher_statements.append(f"    is_override: {str(method_info['is_override']).lower()}")            if method_info['return_type']:                cypher_statements.append(f"    , return_type: '{method_info['return_type']}'")            cypher_statements.append("});")            cypher_statements.append("")            # Create CONTAINS: Class -> Method            cypher_statements.append(f"// Class CONTAINS Method")            cypher_statements.append(f"MATCH (c:Class {{full_name: '{class_info['full_name']}'}})")            cypher_statements.append(f"MATCH (m:Method {{full_name: '{method_info['full_name']}'}})")            cypher_statements.append(f"CREATE (c)-[:CONTAINS]->(m);")            cypher_statements.append("")            # Handle method annotations            for annotation in method_info['annotations']:                entities['annotations'].add(annotation)                cypher_statements.append(f"// Annotation on Method")                cypher_statements.append(f"MERGE (ann:Annotation {{name: '{annotation}'}});")                cypher_statements.append(f"MATCH (a:Annotation {{name: '{annotation}'}})")                cypher_statements.append(f"MATCH (m:Method {{full_name: '{method_info['full_name']}'}})")                cypher_statements.append(f"CREATE (a)-[:ANNOTATES]->(m);")                cypher_statements.append("")            # Handle throws            for exception in method_info['throws']:                entities['exceptions'].add(exception)                cypher_statements.append(f"// Method THROWS Exception")                cypher_statements.append(f"MERGE (exc:Exception {{name: '{exception}'}});")                cypher_statements.append(f"MATCH (m:Method {{full_name: '{method_info['full_name']}'}})")                cypher_statements.append(f"MATCH (e:Exception {{name: '{exception}'}})")                cypher_statements.append(f"CREATE (m)-[:THROWS]->(e);")                cypher_statements.append("")            # Handle catches            for exception in method_info['catches']:                entities['exceptions'].add(exception)                cypher_statements.append(f"// Method CATCHES Exception")                cypher_statements.append(f"MERGE (exc:Exception {{name: '{exception}'}});")                cypher_statements.append(f"MATCH (m:Method {{full_name: '{method_info['full_name']}'}})")                cypher_statements.append(f"MATCH (e:Exception {{name: '{exception}'}})")                cypher_statements.append(f"CREATE (m)-[:CATCHES]->(e);")                cypher_statements.append("")            # Handle method calls            for call in method_info['calls']:                cypher_statements.append(f"// Method CALLS Method")                cypher_statements.append(f"MATCH (m1:Method {{full_name: '{method_info['full_name']}'}})")                cypher_statements.append(f"MERGE (m2:Method {{name: '{call}'}})")                cypher_statements.append(f"CREATE (m1)-[:CALLS]->(m2);")                cypher_statements.append("")    return "\n".join(cypher_statements)def main():    """Generate Cypher from sample Java code"""    java_file = 'sample_code.java'    print("="*60)    print("Java to Neo4j Cypher Generator")    print("="*60)    print(f"Parsing: {java_file}")    print()    cypher = generate_cypher(java_file)    # Save to file    output_file = 'paymentservice_graph.cypher'    with open(output_file, 'w') as f:        f.write(cypher)    print(f"✓ Generated Cypher saved to: {output_file}")    print()    print("="*60)    print("To load into Neo4j:")    print("="*60)    print("1. Open Neo4j Browser")    print("2. Copy the contents of paymentservice_graph.cypher")    print("3. Paste into Neo4j Browser")    print("4. Run the script")    print("5. Visualize with: MATCH (n) RETURN n")    print("="*60)    # Also print a preview    print("\nPreview (first 50 lines):")    print("-"*60)    print("\n".join(cypher.split("\n")[:50]))    print("...")if __name__ == "__main__":    main()